extends Resource
class_name DialogChoice

@export var label: String = ""
@export var next_id: StringName = &""
@export var condition_flag: StringName = &""

extends Resource
class_name DialogNode

@export var id: StringName = &""
@export var speaker: String = ""
@export var text: String = ""
@export var choices: Array[DialogChoice] = []
@export var next_id: StringName = &""

extends Resource
class_name DialogTree

@export var nodes: Array[DialogNode] = []
@export var start_id: StringName = &""

func get_node(id: StringName) -> DialogNode:
	for node in nodes:
		if node and node.id == id:
			return node
	return null

extends Node
class_name DialogPlayer

signal line_shown(speaker: String, text: String, choices_labels: Array)
signal dialog_finished

@export var tree: DialogTree

var current_node: DialogNode = null
var _flags: Dictionary = {}
var _visible_choices: Array[DialogChoice] = []

func set_flag(name: StringName) -> void:
	_flags[name] = true

func has_flag(name: StringName) -> bool:
	return _flags.get(name, false)

func start() -> void:
	_visible_choices.clear()
	if not tree:
		push_error("DialogPlayer: No DialogTree assigned.")
		emit_signal("dialog_finished")
		return

	var node = tree.get_node(tree.start_id)
	if node:
		current_node = node
		_show_current_node()
	else:
		current_node = null
		emit_signal("dialog_finished")

func advance(choice_index: int = -1) -> void:
	if not current_node:
		return

	if current_node.choices.is_empty() and current_node.next_id == &"":
		current_node = null
		emit_signal("dialog_finished")
		return

	if not current_node.choices.is_empty():
		# Node has choices, we must follow the chosen branch
		if choice_index >= 0 and choice_index < _visible_choices.size():
			var choice = _visible_choices[choice_index]
			var next_node = tree.get_node(choice.next_id)
			if next_node:
				current_node = next_node
				_show_current_node()
			else:
				current_node = null
				emit_signal("dialog_finished")
		else:
			push_error("DialogPlayer: Invalid choice index %d" % choice_index)
	else:
		# Node has no choices, follow next_id
		var next_node = tree.get_node(current_node.next_id)
		if next_node:
			current_node = next_node
			_show_current_node()
		else:
			current_node = null
			emit_signal("dialog_finished")

func _show_current_node() -> void:
	_visible_choices.clear()
	var labels: Array = []
	if current_node:
		for choice in current_node.choices:
			if choice:
				if choice.condition_flag == &"" or has_flag(choice.condition_flag):
					_visible_choices.append(choice)
					labels.append(choice.label)
		emit_signal("line_shown", current_node.speaker, current_node.text, labels)

extends Control
class_name DialogUI

@export var player: DialogPlayer

@export var speaker_label: Label
@export var body_text: RichTextLabel
@export var choices_container: VBoxContainer

func _ready() -> void:
	# Fallback to finding them by name/type if not explicitly assigned
	if not speaker_label:
		speaker_label = find_child("SpeakerLabel") as Label
		if not speaker_label:
			speaker_label = find_child("*Speaker*") as Label
	if not body_text:
		body_text = find_child("BodyText") as RichTextLabel
		if not body_text:
			body_text = find_child("*RichText*") as RichTextLabel
	if not choices_container:
		choices_container = find_child("ChoicesContainer") as VBoxContainer
		if not choices_container:
			choices_container = find_child("*VBox*") as VBoxContainer

	if player:
		player.line_shown.connect(_on_line_shown)
		player.dialog_finished.connect(_on_dialog_finished)

func _on_line_shown(speaker: String, text: String, choices_labels: Array) -> void:
	if speaker_label:
		speaker_label.text = speaker
	if body_text:
		body_text.text = text

	if choices_container:
		# Clear existing buttons
		for child in choices_container.get_children():
			child.queue_free()

		if choices_labels.is_empty():
			var button = Button.new()
			button.text = "Continue"
			if player:
				button.pressed.connect(func(): player.advance(-1))
			choices_container.add_child(button)
		else:
			for i in range(choices_labels.size()):
				var label_text = choices_labels[i]
				var button = Button.new()
				button.text = label_text
				if player:
					button.pressed.connect(func(): player.advance(i))
				choices_container.add_child(button)

func _on_dialog_finished() -> void:
	hide()
